UPDATE COTDL.TBL_DISCOVERY_SCAN_RESULT
SET confirm_status = #{confirmStatus},
    confirmed_by = #{userId},
    confirmed_date = NOW(),
    upd_date = NOW()
WHERE db_name = #{dbName}
  AND COALESCE(schema_name, '') = COALESCE(#{schemaName}, '')
  AND table_name = #{tableName}
  AND column_name = #{columnName}
  AND (confirm_status IS NULL OR confirm_status != #{confirmStatus})

mapper.select:
SELECT execution_id
FROM COTDL.TBL_DISCOVERY_SCAN_EXECUTION
WHERE job_id = #{jobId}
  AND status IN ('COMPLETED', 'FAILED', 'CANCELLED')
ORDER BY start_time DESC
LIMIT 999999 OFFSET #{keepCount}

mapper.delete:
DELETE FROM COTDL.TBL_DISCOVERY_SCAN_RESULT
WHERE execution_id IN (
    SELECT execution_id FROM (
        SELECT execution_id
        FROM COTDL.TBL_DISCOVERY_SCAN_EXECUTION
        WHERE job_id = #{jobId}
          AND status IN ('COMPLETED', 'FAILED', 'CANCELLED')
        ORDER BY start_time DESC
        LIMIT 999999 OFFSET #{keepCount}
    ) AS old_executions
)

DELETE FROM COTDL.TBL_DISCOVERY_SCAN_EXECUTION
WHERE execution_id IN (
    SELECT execution_id FROM (
        SELECT execution_id
        FROM COTDL.TBL_DISCOVERY_SCAN_EXECUTION
        WHERE job_id = #{jobId}
          AND status IN ('COMPLETED', 'FAILED', 'CANCELLED')
        ORDER BY start_time DESC
        LIMIT 999999 OFFSET #{keepCount}
    ) AS old_executions
)

