SELECT COUNT(*)
FROM COTDL.TBL_DISCOVERY_PII_REGISTRY r
WHERE r.status = #{search4}

    AND r.db_name = #{search1}


    AND r.schema_name LIKE #{search2}

SELECT DISTINCT table_name
FROM COTDL.TBL_METATABLE
WHERE db = #{db}
  AND owner = #{owner}

  AND table_name LIKE #{tablePattern}

ORDER BY table_name

SELECT db, owner, table_name, column_name, column_id,
       data_type, data_length, column_comment
FROM COTDL.TBL_METATABLE
WHERE db = #{db}
  AND owner = #{owner}
ORDER BY table_name, column_id

