UPDATE COTDL.TBL_METATABLE
SET val2 = NULL,
    upddate = NOW()
WHERE db = #{dbName}
  AND COALESCE(owner, '') = COALESCE(#{schemaName}, '')
  AND table_name = #{tableName}
  AND column_name = #{columnName}

mapper.select:
SELECT db_name AS dbName, schema_name AS schemaName, table_name AS tableName, GROUP_CONCAT(DISTINCT column_name ORDER BY column_name) AS piiColumns, GROUP_CONCAT(DISTINCT pii_type_code ORDER BY pii_type_code) AS piiTypes, COUNT(*) AS columnCount FROM COTDL.TBL_DISCOVERY_PII_REGISTRY WHERE status = 'CONFIRMED'
AND db_name = #{dbName}
GROUP BY db_name, schema_name, table_name ORDER BY db_name, schema_name, table_name

